-- Skillora Clean Database Restore Script
-- 1. Create Tables
CREATE TABLE IF NOT EXISTS public."Users" (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    name character varying,
    email character varying UNIQUE,
    picture character varying,
    credits bigint DEFAULT '3'::bigint
);

CREATE TABLE IF NOT EXISTS public.interviews (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    "jobPosition" character varying,
    "jobDescription" character varying,
    duration character varying,
    type character varying,
    "questionList" json,
    "userEmail" character varying,
    interview_id character varying UNIQUE NOT NULL
);

CREATE TABLE IF NOT EXISTS public."interview-feedback" (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    "userName" character varying,
    "userEmail" character varying,
    interview_id character varying,
    feedback json,
    recommended boolean
);

-- Enable RLS
ALTER TABLE public."Users" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.interviews ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."interview-feedback" ENABLE ROW LEVEL SECURITY;

-- 2. Data Inserts

-- 3. Add Foreign Keys & Constraints after data insert
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint WHERE conname = 'interview-feedback_interview_id_fkey'
    ) THEN
        ALTER TABLE public."interview-feedback" 
        ADD CONSTRAINT "interview-feedback_interview_id_fkey" 
        FOREIGN KEY (interview_id) REFERENCES public.interviews(interview_id) ON DELETE CASCADE;
    END IF;
END $$;
