INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('1', '2025-04-27 15:51:54.531608+00', 'Shreyas', 'jjadhavshreyas84@gmail.com', '720572b1-539c-4940-a2ae-92c0ae6d31d4', '{"feedback":{"rating":{"technicalSkills":5,"communication":6,"problemSolving":4,"experience":7},"summery":"The candidate demonstrated a good understanding of technical concepts, was clear in their communication, and showed ability to break down complex problems. However, there were some areas where they required additional guidance. Overall, their experience in the field was impressive.","Recommendation":"May be acceptable","RecommendationMsg":"With some additional training and guidance, the candidate could be a good fit for the role."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('2', '2025-04-27 16:10:31.442599+00', 'Shreyas', 'Jadhav', '720572b1-539c-4940-a2ae-92c0ae6d31d4', '{"feedback":{"rating":{"technicalSkills":5,"communication":6,"problem Solving":4,"experience":7},"summery":"The user was slightly struggling with the technical aspects, but was able to improve with guidance. They communicated clearly and effectively. They showed good experience in the field, but sometimes relied on past experience instead of exploring alternative solutions.","Recommendation":"Maybe","RecommendationMsg":"This candidate shows promise, but needs more work on their technical skills and problem-solving abilities to be considered for hire."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('3', '2025-04-28 16:08:05.445185+00', 'Shreyas', 'jjadhavshreyas84@gmail.com', '22fc8ef3-478b-44b5-927f-b1718a819099', '{"feedback":{"rating":{"technicalSkills":5,"communication":6,"problem Solving":4,"experience":7},"summary":"The candidate had a good understanding of the technical concepts, but lacked specific examples and details. They communicated well, but had some trouble explaining complex ideas. Overall, they showed strong experience in their field.","Recommendation":"Yes","RecommendationMsg":"I would recommend considering this candidate for the position, but with the condition that they work on improving their technical questioning and problem-solving skills."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('4', '2025-04-29 21:31:38.056932+00', 'Shreyas Jadhav', 'jjadhasvhreyas84@gmail.com', '81b9ca2a-c11d-4d68-82dd-7c062fb0be58', '{"feedback":{"rating":{"technicalSkills":5,"communication":6,"problemSolving":4,"experience":7},"summary":"The user demonstrated a good understanding of programming concepts, but struggled with some specific technical details. They communicated clearly and professionally, but could improve their problem-solving skills. Overall, they showed a strong foundation in their field.","recommendation":"Maybe","recommendationMsg":"While they showed some strong skills, they need to work on refining their technical skills and problem-solving abilities to be a top candidate."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('5', '2025-04-29 21:31:38.069467+00', 'Shreyas Jadhav', 'jjadhasvhreyas84@gmail.com', '81b9ca2a-c11d-4d68-82dd-7c062fb0be58', '{"feedback":{"rating":{"techicalSkills":7,"communication":8,"problem Solving":8,"experince":9},"summery":"The user demonstrated strong technical skills, good communication, and impressive problem-solving abilities. They provided clear and concise answers to technical questions. Overall, the interview was engaging and well-structured.","Recommendation":"Highly Recommended","RecommendationMsg":"You''ve got a strong candidate here! With a bit more practice in problem-solving, they''ll be a great fit for your team."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('6', '2025-06-11 09:27:55.281446+00', 'Jaysingh Verma', 'jaysinghverma121@gmail.com', '82cf2064-3804-4fb9-a965-eaa3786c7130', '{"feedback":{"rating":{"technicalSkills":7,"communication":8,"problem Solving":6,"experience":9},"summery":"The interviewee showed strong coding skills, good communication, and decent problem-solving skills. They were able to answer technical questions with ease and provided clear explanations. However, there were some moments of hesitation when faced with complex problems.","Recommendation":"Somewhat Recommended","RecommendationMsg":"While the interviewee showed potential, they need to work on improving their problem-solving skills to tackle complex technical challenges with confidence."}}', 'f') ON CONFLICT DO NOTHING;
