INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('9', '2025-06-11 09:55:18.510679+00', 'Eashita', 'shahxv@gmail.com', '82cf2064-3804-4fb9-a965-eaa3786c7130', '{"feedback":{"rating":{"technicalSkills":6,"communication":8,"problemSolving":7,"experience":9},"summary":"The candidate showcased excellent technical skills and experience in the field. However, there were some minor issues with communication and problem-solving. The candidate could improve in these areas with further practice.","recommendation":"Yes","recommendationMsg":"I would recommend this candidate for the position with some minor adjustments in their communication and problem-solving skills."}}', 'f') ON CONFLICT DO NOTHING;
