INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('11', '2025-06-11 10:57:45.753312+00', 'Neha', 'neha@gmail.com', '82cf2064-3804-4fb9-a965-eaa3786c7130', '{"feedback":{"rating":{"technicalSkills":8,"communication":9,"problemSolviing":6,"experince":8},"summery":"The user was well-prepared and demonstrated a strong understanding of technical concepts. They effectively communicated their thoughts and ideas, but struggled at times with problem-solving. They also highlighted their relevant work experience.","Recommendation":"Yes","RecommendationMsg":"Based on this interview, I would highly recommend this candidate for hire."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('12', '2025-06-12 04:43:38.526332+00', 'ram', 'ram@gmail.com', '82cf2064-3804-4fb9-a965-eaa3786c7130', '{"feedback":{"rating":{"technicalSkills":6,"communication":8,"problemSoloving":5,"experience":8},"summery":"The candidate had good understanding of the technical aspects, clear communication skills, and adequate problem-solving skills. However, there were some areas where improvement was required. Overall, they had relevant experience in the field.","Recommendation":"Recommended","RecommendationMsg":"Please note that with some guidance, this candidate has the potential to become a valuable team member."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public."interview-feedback" (id, created_at, "userName", "userEmail", interview_id, feedback, recommended) VALUES ('13', '2025-06-24 09:18:16.435184+00', 'Eashita', 'eashitakkara@gmail.com', '82cf2064-3804-4fb9-a965-eaa3786c7130', '{"feedback":{"rating":{"technicalSkills":7,"communication":8,"problemSolving":6,"experience":8},"summery":"The user showcased strong expertise in the field, with a clear and concise communication style. They were able to provide relevant examples from their experience and demonstrated a good understanding of the concepts. However, there were a few instances where they struggled with solving complex problems.","Recommendation":"Recommended","RecommendationMsg":"Based on the interview, the user exhibits a strong set of skills and qualities, and therefore, we recommend hiring them."}}', 'f') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('1', '2025-04-27 06:13:46.280476+00', 'Full Stack', 'We''re looking for a skilled Full Stack Frontend Developer with expertise in React.js to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop responsive, dynamic web applications using React\n\nIntegrate frontend with backend services/APIs\n\nOptimize performance, accessibility, and SEO\n\nWrite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6+)\n\nExperience with REST/GraphQL APIs\n\nFamiliar with backend (Node.js/Express or similar)\n\nVersion control with Git\n\nKnowledge of databases (SQL/NoSQL) is a plus', '15 Min', '["Technical","Behavioral"]', '[{"question":"Can you tell me about your experience with React.js? How have you used it in previous projects?","type":"Technical"},{"question":"What is your approach to debugging and solvingissues in complex React applications?","type":"Technical"},{"question":"How do you ensure responsive and dynamic user interfaces in your React applications?","type":"Technical"},{"question":"Can you describe a project where you had to integrate a frontend application with a backend API? What challenges did you face and how did you overcome them?","type":"Technical"},{"question":"What metrics do you use to measure the performance of a React application? How do you optimize them?","type":"Technical"},{"question":"Can you walk me through your process of writing clean, maintainable code and conducting code reviews?","type":"Technical"},{"question":"How do you stay up-to-date with the latest developments in React and frontend development in general?","type":"Technical"},{"question":"Can you describe a time when you had to collaborate with a cross-functional team to ship a feature quickly? What was your role and how did you contribute to the team?","type":"Behavioral"},{"question":"How do you handle conflicts or disagreements with team members during a code review or feature development?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', 'c2dc8462-cba8-4d01-8fee-c618ab126356') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('2', '2025-04-27 07:21:43.512252+00', 'Full Stack', 'We''re looking for a skilled Full Stack Frontend Developer with expertise in React.js to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop responsive, dynamic web applications using React\n\nIntegrate frontend with backend services/APIs\n\nOptimize performance, accessibility, and SEO\n\nWrite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6+)\n\nExperience with REST/GraphQL APIs\n\nFamiliar with backend (Node.js/Express or similar)\n\nVersion control with Git\n\nKnowledge of databases (SQL/NoSQL) is a plus', '15 Min', '["Technical","Behavioral"]', '[{"question":"Can you tell me about your experience with React.js? How have you used it in previous projects?","type":"Technical"},{"question":"What is your approach to debugging and solvingissues in complex React applications?","type":"Technical"},{"question":"How do you ensure responsive and dynamic user interfaces in your React applications?","type":"Technical"},{"question":"Can you describe a project where you had to integrate a frontend application with a backend API? What challenges did you face and how did you overcome them?","type":"Technical"},{"question":"What metrics do you use to measure the performance of a React application? How do you optimize them?","type":"Technical"},{"question":"Can you walk me through your process of writing clean, maintainable code and conducting code reviews?","type":"Technical"},{"question":"How do you stay up-to-date with the latest developments in React and frontend development in general?","type":"Technical"},{"question":"Can you describe a time when you had to collaborate with a cross-functional team to ship a feature quickly? What was your role and how did you contribute to the team?","type":"Behavioral"},{"question":"How do you handle conflicts or disagreements with team members during a code review or feature development?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', 'a399a126-819d-485a-897c-45e073874473') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('3', '2025-04-27 08:57:34.855265+00', 'Full Stack Developer', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Technical","Behavioral"]', '[{"question":"Can you explain the concept of a single-page application (SPA) and how React.js contributes to it?","type":"Technical"},{"question":"How do you optimize the performance of a React application? Can you give an example?","type":"Technical"},{"question":"What is your experience with REST/GraphQL APIs? Can you walk me through a scenario where you integrated a frontend with a backend service?","type":"Technical"},{"question":"Can you describe a situation where you had to debug a complex issue in a React application? How did you approach it?","type":"Technical/Behavioral"},{"question":"How do you stay up-to-date with the latest developments in React and JavaScript? Can you recommend any resources?","type":"Behavioral"},{"question":"Can you explain the concept of server-side rendering (SSR) with React? How do you see it impacting the application?","type":"Technical"},{"question":"Have you worked with version control systems like Git? Can you walk me through a recent experience where you had to resolve a merge conflict?","type":"Technical"},{"question":"Can you describe a project where you worked collaboratively with a backend developer to integrate a frontend and backend service?","type":"Technical/Behavioral"},{"question":"How do you approach accessibility in your React applications? Can you give an example of a technique you used?","type":"Technical"},{"question":"Can you explain the concept of React hooks and how they differ from traditional class components?","type":"Technical"},{"question":"Can you describe a situation where you had to balance competing priorities and deadlines in a project? How did you handle it?","type":"Behavioral"},{"question":"Can you explain the concept of a DevOps pipeline and how you''ve implemented it in your previous projects?","type":"Technical"}]', 'jjadhavshreyas84@gmail.com', '726e6cd3-635b-44b2-bccf-4911807b1841') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('4', '2025-04-27 08:58:22.544376+00', 'Full Stack Developer', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Experience","Behavioral"]', '[{"question":"Can you explain your experience with React.js and how you''ve used it in previous projects?","type":"Experience"},{"question":"How do you approach responsive design and developing dynamic web applications using React?","type":"Technical"},{"question":"What is your favorite way to optimize performance, accessibility, and SEO in a frontend application? Can you give an example?","type":"Technical"},{"question":"Can you walk me through your process for integrating frontend with backend services/APIs using REST/GraphQL?","type":"Technical"},{"question":"How do you handle code reviews and contribute to a clean, maintainable codebase?","type":"Behavioral"},{"question":"Can you describe a project where you worked closely with a cross-functional team to ship features quickly? What was your role in the process?","type":"Behavioral"},{"question":"What is your experience with version control using Git, and how do you handle conflicts or merges?","type":"Experience"},{"question":"How do you stay up-to-date with the latest developments and best practices in the React ecosystem?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', '87efa67b-f0d3-4164-9bf9-8b3a70e1abee') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('5', '2025-04-27 09:01:54.17574+00', 'Full Stack Developer', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Experience","Behavioral"]', '[{"question":"Can you explain your experience with React.js and how you''ve used it in previous projects?","type":"Experience"},{"question":"How do you approach responsive design and developing dynamic web applications using React?","type":"Technical"},{"question":"What is your favorite way to optimize performance, accessibility, and SEO in a frontend application? Can you give an example?","type":"Technical"},{"question":"Can you walk me through your process for integrating frontend with backend services/APIs using REST/GraphQL?","type":"Technical"},{"question":"How do you handle code reviews and contribute to a clean, maintainable codebase?","type":"Behavioral"},{"question":"Can you describe a project where you worked closely with a cross-functional team to ship features quickly? What was your role in the process?","type":"Behavioral"},{"question":"What is your experience with version control using Git, and how do you handle conflicts or merges?","type":"Experience"},{"question":"How do you stay up-to-date with the latest developments and best practices in the React ecosystem?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', '2fa971a9-4546-4f21-b42f-3bf0347fba45') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('6', '2025-04-27 09:02:29.663364+00', 'Full Stack Develper', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Technical","Behavioral"]', '[{"question":"Can you explain the concept of a closure in JavaScript? Provide an example of its usage.","type":"Technical"},{"question":"What is your favorite React feature, and how have you used it in your projects?","type":"Technical"},{"question":"Describe a situation where you optimized the performance of a web application.","type":"Behavioral"},{"question":"How do you handle errors and exceptions in a React application? Provide an example.","type":"Technical"},{"question":"Can you walk me through your process of building a RESTful API using Node.js and Express?","type":"Technical"},{"question":"Tell me about a time when you had to collaborate with a team to resolve a complex technical issue.","type":"Behavioral"},{"question":"What is your experience with Git? Can you explain how you handle conflicts and resolve merge issues?","type":"Technical"},{"question":"Can you describe the difference between SQL and NoSQL databases? When would you choose to use each?","type":"Technical"},{"question":"How do you ensure responsive design in your web applications? Provide an example of a technique you''ve used.","type":"Technical"},{"question":"Can you explain the concept of a controlled component in React? Provide an example of its usage.","type":"Technical"},{"question":"Describe your experience with React Hooks. Can you provide an example of how you''ve used them?","type":"Technical"}]', 'jjadhavshreyas84@gmail.com', '123218d0-4cbe-44b0-b0ab-e086558294f0') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('7', '2025-04-27 09:05:43.194319+00', 'Full Stack Developer', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Technical","Behavioral"]', '[{"question":"What is React, and why do you choose to use it for building web applications?","type":"Technical"},{"question":"Can you explain the concept of a unified state management system in React? How would you implement it?","type":"Technical"},{"question":"How do you optimize the performance of a React application? Can you give an example?","type":"Technical"},{"question":"What is your approach to maintaining code quality and ensuring code reviews are effective?","type":"Behavioral"},{"question":"Can you describe your experience with REST/GraphQL APIs? How do you decide which one to use in a project?","type":"Technical"},{"question":"How do you ensure compatibility and responsiveness across different devices and browsers?","type":"Technical"},{"question":"Can you explain the principles of accessibility in web development and give an example of how you implement them?","type":"Technical"},{"question":"Can you walk us through your experience with version control systems like Git? How do you handle conflicts?","type":"Technical"},{"question":"How do you prioritize and manage your work when working on a complex project with multiple dependencies?","type":"Behavioral"},{"question":"Can you describe your experience with backend technologies like Node.js and Express? How do you integrate frontend and backend code?","type":"Technical"},{"question":"How do you handle errors and debugging in your code? Can you give an example of a creative solution?","type":"Technical"},{"question":"Can you explain the importance of scalability and maintainability in web development? How do you design your code to be scalable and maintainable?","type":"Technical"}]', 'jjadhavshreyas84@gmail.com', '81b9ca2a-c11d-4d68-82dd-7c062fb0be58') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('8', '2025-04-27 09:22:28.865796+00', 'Full Stack', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '15 Min', '["Technical","Behavioral"]', '[{"question":"What is React and what are its key features?","type":"Technical"},{"question":"How do you handle state management in a complex React application? Can you give an example?","type":"Technical"},{"question":"Can you explain the concept of a higher-order component in React? When would you use it?","type":"Technical"},{"question":"What is your experience with REST/GraphQL APIs? Can you walk me through how you integrate them with a React application?","type":"Technical"},{"question":"How do you approach performance optimization in a React application? Can you give an example of a technique you''ve used?","type":"Technical"},{"question":"What is your take on code architecture and organization in a large React application? Can you give an example of how you''ve structured your code?","type":"Technical"},{"question":"Can you describe how you handled a difficult bug in a React application? How did you debug and resolve it?","type":"Problem Solving"},{"question":"How do you stay up-to-date with the latest developments and trends in the React ecosystem? Can you give an example of something new you''ve learned recently?","type":"Behavioral"},{"question":"Can you walk me through your experience with collaboration and communication with cross-functional teams? How do you handle conflicting opinions or priorities?","type":"Behavioral"},{"question":"What tools and technologies do you use for version control and how do you approach branch management in a team?","type":"Technical"},{"question":"Can you describe a situation where you had to make a difficult technical decision? What factors influenced your decision and what was the outcome?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', 'dbb6a173-6500-49e2-b47a-716e302b027a') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('9', '2025-04-27 09:27:42.938679+00', 'Full Stack Developer', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Behavioral"]', '[{"question":"Can you explain the concept of React and its role in building scalable web applications?","type":"Technical"},{"question":"How do you handle the integration of frontend with backend services/APIs in your projects? Provide a specific example.","type":"Technical"},{"question":"What are the best practices you follow to ensure performance, accessibility, and SEO optimization in your web applications?","type":"Technical"},{"question":"How do you approach code review and ensure that your code is clean, maintainable, and scalable? Provide a specific example.","type":"Technical"},{"question":"Can you describe a recent project where you collaborated with cross-functional teams to ship features quickly? What was your role, and how did you contribute to the project?","type":"Behavioral"},{"question":"What is your approach to debugging and troubleshooting complex issues in your code? Provide a specific example.","type":"Technical"},{"question":"How do you stay up-to-date with the latest developments and best practices in the React ecosystem? Can you give an example of a new technology or feature you''ve recently adopted?","type":"Experince"},{"question":"Can you walk me through your experience with REST/GraphQL APIs? How do you decide which one to use in a project?","type":"Technical"},{"question":"How do you manage conflicts or differing opinions when working in a team? Provide a recent example.","type":"Behavioral"},{"question":"Can you explain your experience with Git and version control systems? How do you handle merge conflicts and code reviews?","type":"Technical"},{"question":"How do you approach testing and validation of your code? Can you give an example of a testing framework or library you''ve used?","type":"Technical"},{"question":"Can you describe your experience with databases (SQL/NoSQL)? How do you decide which type to use in a project?","type":"Technical"}]', 'jjadhavshreyas84@gmail.com', '3e680d91-b6e4-4fc7-ab19-4d9556e18ac0') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('10', '2025-04-27 09:31:04.286019+00', 'Full Stack ', 'We''re looking for a skilled Full Stack Frontend Developer witt expertise in Reactjs to build and maintain scalable, user- friendly web applications. You''ll collaborate with backend developers, designers, and product teams to create seamless UI/UX experiences and contribute to both frontend and backend codebases.\n\nKey Responsibilities:\n\nDevelop gesponsive, dynamic web applications using React\n\nIntegrate frontend with backend senices/APIis\n\nOptimize performance, accessibility, and SED\n\nWhite clean, maintainable code and conduct code reviews\n\nCollaborate across teams to ship features quickly\n\nRequirements:\n\nProficient in React.js, HTML, CSS, JavaScript (ES6)\n\nExperience with REST/GraphQL APIs\n\nFamilliar with backand (Node.js/Express or simillar)\n\nVersion canthal with Git\n\nKinowledge off databases (SQL/No601) is a plus', '5 Min', '["Technical","Behavioral"]', '[{"question":"Can you explain the concept of React Fiber and how it improves the performance of your application?","type":"Technical"},{"question":"How would you approach debugging a complex issue with React components in your application?","type":"Problem Solving"},{"question":"What do you think is more important, scalability or maintainability, and why?","type":"Behavioral"},{"question":"Have you worked with REST/GraphQL APIs before? Can you give an example of an API you''ve integrated with React?","type":"Technical"},{"question":"Can you explain the concept of state management in React and how you would implement it in a project?","type":"Technical"},{"question":"How do you ensure code quality and maintainability in a large React application?","type":"Technical"},{"question":"Can you walk me through a situation where you had to collaborate with a backend developer to fix an issue?","type":"Behavioral"},{"question":"What libraries or tools do you use to optimize the performance of your React application?","type":"Technical"},{"question":"Have you worked with CSS preprocessors like Sass or Less? Can you explain the benefits and drawbacks of using them?","type":"Technical"},{"question":"Can you explain the concept of event delegation in React and how it can improve the performance of your application?","type":"Technical"},{"question":"Can you describe a project you worked on where you had to prioritize scalability and performance?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', '720572b1-539c-4940-a2ae-92c0ae6d31d4') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('11', '2025-04-28 16:04:43.011504+00', 'Full Stack ', 'Ract Developer forntend devolper', '5 Min', '["Technical","Behavioral"]', '[{"question":"Can you explain the key differences between React, Angular, and Vue.js?","type":"Technical"},{"question":"How would you approach debugging a complex issue in a React application?","type":"Technical"},{"question":"What is your experience with state management libraries like Redux or MobX?","type":"Experience"},{"question":"Can you describe a time when you had to optimize the performance of a React application?","type":"Behavioral"},{"question":"Imagine you''re building a new feature in a React application. How would you architect the component structure?","type":"Problem Solving"},{"question":"Can you demonstrate your understanding of React Hooks and how you would use them in a real-world scenario?","type":"Technical"},{"question":"How do you handle errors and exceptions in a React application?","type":"Technical"},{"question":"Can you walk me through your experience with React testing libraries like Jest or Enzyme?","type":"Experience"},{"question":"Can you describe your approach to handling multiple data sources in a React application?","type":"Problem Solving"},{"question":"Have you worked with any front-end build tools like Webpack or Rollup? If so, can you explain how they work?","type":"Technical"}]', NULL, '22fc8ef3-478b-44b5-927f-b1718a819099') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('12', '2025-06-10 11:50:02.926619+00', 'Frontend Developer', 'react,figma,ui ux desgine', '5 Min', '["Technical","Behavioral"]', '[{"question":"What is your experience with React, and how do you stay up-to-date with its latest developments?","type":"Technical/Experience"},{"question":"Can you explain the difference between var, let, and const keywords in JavaScript? When would you use each one?","type":"Technical"},{"question":"How do you approach accessibility in your frontend development work?","type":"Technical"},{"question":"What is your favorite UI/UX design tool? How do you use it to improve your development workflow?","type":"Technical/Behavioral"},{"question":"If you had to debug a slow-loading web page, what steps would you take to identify the bottleneck and optimize the performance?","type":"Problem Solving"},{"question":"How do you handle prioritizing multiple competing tasks in a fast-paced development environment?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', '82cf2064-3804-4fb9-a965-eaa3786c7130') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('13', '2025-06-24 09:20:33.492147+00', 'Frontend developer', 'React,Figma', '5 Min', '["Technical","Problem Solving"]', '[{"question":"What is your experience with React, and how have you used it in previous projects?","type":"Experience"},{"question":"Can you explain the concept of a closure in JavaScript, and provide an example of how you''ve used it in your code?","type":"Technical"},{"question":"How do you approach debugging a React application? Can you walk me through a time when you encountered an issue and how you solved it?","type":"Problem Solving"},{"question":"Can you describe the difference between a functional component and a class component in React? When would you choose to use each?","type":"Technical"},{"question":"You are given a React component that renders a list of items. How would you optimize its performance for a large dataset?","type":"Problem Solving"},{"question":"Have you worked with Figma before? Can you explain how you use it in your workflow, and what tools you use to collaborate with designers?","type":"Experience"},{"question":"Can you write a simple React component that takes in a prop and renders it to the DOM?","type":"Technical"},{"question":"How do you stay up-to-date with the latest developments in the React ecosystem? Can you give me an example of a new feature or library you''ve learned about recently?","type":"Experience"},{"question":"Can you describe your experience with state management libraries such as Redux or MobX? How have you used them in previous projects?","type":"Experience"}]', 'jjadhavshreyas84@gmail.com', 'df5cd65f-154a-4c43-9c0e-b1298eb77505') ON CONFLICT DO NOTHING;
INSERT INTO public.interviews (id, created_at, "jobPosition", "jobDescription", duration, type, "questionList", "userEmail", interview_id) VALUES ('14', '2025-08-25 11:04:33.295461+00', 'full stack devoplper', 'next.js,react.js,node.js', '5 Min', '["Technical","Behavioral"]', '[{"question":"What is Next.js and how does it differ from React?","type":"Technical"},{"question":"Can you explain the concept of client-side rendering in React?","type":"Technical"},{"question":"How would you handle error handling in a Next.js application?","type":"Technical"},{"question":"Have you worked with Server-Side Rendering (SSR) in Node.js? Can you give an example?","type":"Technical"},{"question":"What are some best practices for optimizing page load times in Next.js?","type":"Technical"},{"question":"Why is it important to separate concerns between state and props in React?","type":"Technical"},{"question":"How do you handle conflicts between different dependencies in a Node.js project?","type":"Technical"},{"question":"Can you explain the concept of memorization in React and how to use it effectively?","type":"Technical"},{"question":"How would you approach debugging a complex issue in a Next.js application?","type":"Technical"},{"question":"What are some popular libraries or frameworks that you''ve used in combination with Next.js?","type":"Technical"},{"question":"Can you walk me through a recent project you''ve worked on that utilized Next.js?","type":"Behavioral"},{"question":"How do you stay current with new developments and updates in the world of React and Next.js?","type":"Behavioral"},{"question":"Can you describe a time when you had to work with a complex, legacy codebase in a React or Next.js project?","type":"Behavioral"}]', 'jjadhavshreyas84@gmail.com', 'c0f4a7c5-13d5-4888-ab00-06b77f848b05') ON CONFLICT DO NOTHING;
